import 'package:flutter/material.dart';import 'todo_model.dart';import 'todo_item.dart';void main() {  runApp(const MaterialApp(debugShowCheckedModeBanner: false, home: TodoApp()));}class TodoApp extends StatefulWidget {  const TodoApp({Key? key}) : super(key: key);  @override  State<TodoApp> createState() => _TodoAppState();}class _TodoAppState extends State<TodoApp> {  // Dữ liệu chỉ lưu trên RAM (tắt app là mất)  List<Todo> _todos = [];  List<Todo> _foundTodos = [];  int _filterIndex = 0; // 0: Tất cả, 1: Chưa xong, 2: Đã xong  final TextEditingController _searchController = TextEditingController();  // --- LOGIC TÌM KIẾM & LỌC ---  void _runFilterAndSearch(String keyword) {    List<Todo> results = [];    // 1. Lọc theo Tab    if (_filterIndex == 0) {      results = _todos;    } else if (_filterIndex == 1) {      results = _todos.where((item) => !item.isCompleted).toList();    } else {      results = _todos.where((item) => item.isCompleted).toList();    }    // 2. Lọc theo từ khóa tìm kiếm    if (keyword.isNotEmpty) {      results = results          .where(            (item) => item.title.toLowerCase().contains(keyword.toLowerCase()),          )          .toList();    }    setState(() {      _foundTodos = results;    });  }  // --- CÁC HÀM XỬ LÝ (Không còn Save/Load) ---  // Hàm xóa  void _deleteTodo(Todo todo) {    setState(() {      _todos.remove(todo);      _runFilterAndSearch(_searchController.text); // Cập nhật lại list hiển thị    });  }  // Hàm đổi trạng thái (Xong/Chưa xong)  void _toggleStatus(Todo todo, bool value) {    setState(() {      todo.isCompleted = value;      _runFilterAndSearch(_searchController.text);    });  }  // Hàm hiển thị Dialog Thêm/Sửa  void _showAddEditDialog({Todo? todoToEdit}) {    final TextEditingController _controller = TextEditingController();    DateTime? _selectedDeadline;    // Nếu là sửa, điền dữ liệu cũ vào    if (todoToEdit != null) {      _controller.text = todoToEdit.title;      _selectedDeadline = todoToEdit.deadline;    }    showDialog(      context: context,      builder: (context) {        // StatefulBuilder để cập nhật giao diện TRONG Dialog (khi chọn ngày giờ)        return StatefulBuilder(          builder: (context, setStateDialog) {            return AlertDialog(              shape: RoundedRectangleBorder(                borderRadius: BorderRadius.circular(20),              ),              title: Text(                todoToEdit == null ? 'Thêm công việc' : 'Sửa công việc',              ),              content: Column(                mainAxisSize: MainAxisSize.min,                children: [                  TextField(                    controller: _controller,                    autofocus: true,                    decoration: InputDecoration(                      hintText: "Nhập nội dung...",                      border: OutlineInputBorder(                        borderRadius: BorderRadius.circular(12),                      ),                    ),                  ),                  const SizedBox(height: 15),                  // Nút chọn ngày giờ                  Row(                    children: [                      Expanded(                        child: OutlinedButton.icon(                          icon: const Icon(Icons.calendar_today, size: 18),                          label: Text(                            _selectedDeadline == null                                ? "Chọn hạn chót"                                : "${_selectedDeadline!.day}/${_selectedDeadline!.month} ${_selectedDeadline!.hour}:${_selectedDeadline!.minute}",                            style: TextStyle(                              color: _selectedDeadline == null                                  ? Colors.grey                                  : Colors.teal,                            ),                          ),                          onPressed: () async {                            // 1. Chọn ngày                            final DateTime? date = await showDatePicker(                              context: context,                              initialDate: _selectedDeadline ?? DateTime.now(),                              firstDate: DateTime.now(),                              lastDate: DateTime(2100),                            );                            if (date == null) return;                            // 2. Chọn giờ                            final TimeOfDay? time = await showTimePicker(                              context: context,                              initialTime: TimeOfDay.fromDateTime(                                _selectedDeadline ?? DateTime.now(),                              ),                            );                            if (time == null) return;                            // 3. Cập nhật biến tạm trong Dialog                            setStateDialog(() {                              _selectedDeadline = DateTime(                                date.year,                                date.month,                                date.day,                                time.hour,                                time.minute,                              );                            });                          },                        ),                      ),                      // Nút xóa ngày đã chọn                      if (_selectedDeadline != null)                        IconButton(                          icon: const Icon(Icons.close, color: Colors.grey),                          onPressed: () {                            setStateDialog(() => _selectedDeadline = null);                          },                        ),                    ],                  ),                ],              ),              actions: [                TextButton(                  onPressed: () => Navigator.pop(context),                  child: const Text('Hủy'),                ),                FilledButton(                  onPressed: () {                    if (_controller.text.trim().isEmpty) return;                    // Cập nhật dữ liệu chính                    setState(() {                      if (todoToEdit == null) {                        // Thêm mới                        _todos.add(                          Todo(                            id: DateTime.now().toString(),                            title: _controller.text.trim(),                            deadline: _selectedDeadline,                          ),                        );                      } else {                        // Sửa                        todoToEdit.title = _controller.text.trim();                        todoToEdit.deadline = _selectedDeadline;                      }                      // Refresh lại danh sách tìm kiếm                      _runFilterAndSearch(_searchController.text);                    });                    Navigator.pop(context);                  },                  child: const Text('Lưu'),                ),              ],            );          },        );      },    );  }  // Dialog xác nhận xóa  void _confirmDelete(Todo todo) {    showDialog(      context: context,      builder: (context) => AlertDialog(        title: const Text("Xác nhận"),        content: const Text("Bạn có muốn xóa công việc này không?"),        actions: [          TextButton(            onPressed: () => Navigator.pop(context),            child: const Text("Hủy"),          ),          ElevatedButton(            style: ElevatedButton.styleFrom(              backgroundColor: Colors.red[50],              foregroundColor: Colors.red,            ),            onPressed: () {              _deleteTodo(todo);              Navigator.pop(context);            },            child: const Text("Xóa"),          ),        ],      ),    );  }  @override  Widget build(BuildContext context) {    return Theme(      data: ThemeData(        useMaterial3: true,        colorScheme: ColorScheme.fromSeed(seedColor: Colors.teal),      ),      child: Scaffold(        backgroundColor: Colors.grey[50],        appBar: AppBar(          title: const Text('Todo Simple'),          backgroundColor: Colors.teal,          foregroundColor: Colors.white,          elevation: 0,        ),        body: Column(          children: [            // Ô Tìm kiếm            Container(              padding: const EdgeInsets.all(16),              color: Colors.teal,              child: TextField(                controller: _searchController,                onChanged: _runFilterAndSearch,                decoration: InputDecoration(                  hintText: 'Tìm kiếm...',                  prefixIcon: const Icon(Icons.search),                  filled: true,                  fillColor: Colors.white,                  border: OutlineInputBorder(                    borderRadius: BorderRadius.circular(30),                    borderSide: BorderSide.none,                  ),                  contentPadding: const EdgeInsets.symmetric(vertical: 0),                ),              ),            ),            // Bộ lọc Chips            Container(              padding: const EdgeInsets.symmetric(vertical: 10),              color: Colors.white,              child: Row(                mainAxisAlignment: MainAxisAlignment.center,                children: [                  _buildFilterChip("Tất cả", 0),                  const SizedBox(width: 10),                  _buildFilterChip("Chưa xong", 1),                  const SizedBox(width: 10),                  _buildFilterChip("Đã xong", 2),                ],              ),            ),            // Danh sách hiển thị            Expanded(              child: _foundTodos.isEmpty                  ? Center(                      child: Text(                        _todos.isEmpty ? "Danh sách trống" : "Không tìm thấy",                        style: TextStyle(color: Colors.grey),                      ),                    )                  : ListView.builder(                      padding: const EdgeInsets.only(bottom: 80, top: 10),                      itemCount: _foundTodos.length,                      itemBuilder: (context, index) {                        // Lấy item từ danh sách đã lọc                        final todo = _foundTodos[index];                        return TodoItemWidget(                          todo: todo,                          onStatusChanged: (v) => _toggleStatus(todo, v!),                          onEdit: () => _showAddEditDialog(todoToEdit: todo),                          onDelete: () => _confirmDelete(todo),                        );                      },                    ),            ),          ],        ),        floatingActionButton: FloatingActionButton(          onPressed: () => _showAddEditDialog(),          backgroundColor: Colors.teal,          child: const Icon(Icons.add, color: Colors.white),        ),      ),    );  }  Widget _buildFilterChip(String label, int index) {    return ChoiceChip(      label: Text(label),      selected: _filterIndex == index,      onSelected: (bool selected) {        setState(() {          _filterIndex = index;          _runFilterAndSearch(_searchController.text);        });      },    );  }}